import { Routes } from '@angular/router';
import { InvoiceListComponent } from './components/invoice-list/invoice-list.component';
import { InvoiceFormComponent } from './components/invoice-form/invoice-form.component';
import { InvoicePreviewComponent } from './components/invoice-preview/invoice-preview.component';

export const routes: Routes = [
  { path: '', redirectTo: 'invoices', pathMatch: 'full' },

  { path: 'invoices', component: InvoiceListComponent },
  { path: 'invoices/new', component: InvoiceFormComponent },

  // Variantes (au cas ou)
  { path: 'invoices/:id/edit', component: InvoiceFormComponent },
  { path: 'invoices/:id/preview', component: InvoicePreviewComponent },

  // Fallback si ton projet utilise l'autre format
  { path: 'invoices/preview/:id', component: InvoicePreviewComponent },

  { path: 'estimation', loadComponent: () => import('./components/estimation/estimation.component').then(m => m.EstimationComponent) },
  { path: 'stock', loadComponent: () => import('./components/stock/stock.component').then(m => m.StockComponent) },
  { path: 'stock/history', loadComponent: () => import('./components/stock-history/stock-history.component').then(m => m.StockHistoryComponent) },

  { path: '**', redirectTo: 'invoices' }
];
